Bash(node -e "
const zlib = require\('zlib'\);
const fs = require\('fs'\);

const W = 192, H = 192;
// Orange bg: #FF5E1A, dark navy: #09081A, white: #FFFFFF

// Build raw pixel data \(RGBA\)
const pixels = Buffer.alloc\(W * H * 4\);
for \(let y = 0; y < H; y++\) {
  for \(let x = 0; x < W; x++\) {
    const i = \(y * W + x\) * 4;
    // Background: orange #FF5E1A
    pixels[i] = 0xFF;
    pixels[i+1] = 0x5E;
    pixels[i+2] = 0x1A;
    pixels[i+3] = 0xFF;
  }
}

// Draw a bold 'T' in white
// T dimensions: roughly centered, athletic/bold style
// Horizontal bar: y=40..64, x=40..152
// Vertical stem: y=64..152, x=76..116
function setPixel\(x, y, r, g, b\) {
  if \(x < 0 || x >= W || y < 0 || y >= H\) return;
  const i = \(y * W + x\) * 4;
  pixels[i] = r; pixels[i+1] = g; pixels[i+2] = b; pixels[i+3] = 0xFF;
}
function fillRect\(x1, y1, x2, y2, r, g, b\) {
  for \(let y = y1; y < y2; y++\)
    for \(let x = x1; x < x2; x++\)
      setPixel\(x, y, r, g, b\);
}

// White T
fillRect\(36, 38, 156, 68, 255, 255, 255\);  // top bar
fillRect\(76, 68, 116, 156, 255, 255, 255\); // stem

// Subtle dark border/shadow on T for depth
fillRect\(36, 36, 156, 38, 9, 8, 26\);   // top edge
fillRect\(36, 68, 76, 70, 9, 8, 26\);    // left notch bottom
fillRect\(116, 68, 156, 70, 9, 8, 26\);  // right notch bottom

// Build PNG
// PNG filter: type 0 \(None\) for each row
const rawData = Buffer.alloc\(H * \(1 + W * 4\)\);
for \(let y = 0; y < H; y++\) {
  rawData[y * \(1 + W * 4\)] = 0; // filter byte
  pixels.copy\(rawData, y * \(1 + W * 4\) + 1, y * W * 4, \(y + 1\) * W * 4\);
}

const compressed = zlib.deflateSync\(rawData\);

function crc32\(buf\) {
  let c = 0xFFFFFFFF;
  const table = new Int32Array\(256\);
  for \(let n = 0; n < 256; n++\) {
    let cc = n;
    for \(let k = 0; k < 8; k++\) cc = \(cc & 1\) ? \(0xEDB88320 ^ \(cc >>> 1\)\) : \(cc >>> 1\);
    table[n] = cc;
  }
  for \(let i = 0; i < buf.length; i++\) c = table[\(c ^ buf[i]\) & 0xFF] ^ \(c >>> 8\);
  return \(c ^ 0xFFFFFFFF\) >>> 0;
}

function chunk\(type, data\) {
  const len = Buffer.alloc\(4\);
  len.writeUInt32BE\(data.length\);
  const typeData = Buffer.concat\([Buffer.from\(type\), data]\);
  const crc = Buffer.alloc\(4\);
  crc.writeUInt32BE\(crc32\(typeData\)\);
  return Buffer.concat\([len, typeData, crc]\);
}

const sig = Buffer.from\([137, 80, 78, 71, 13, 10, 26, 10]\);

const ihdr = Buffer.alloc\(13\);
ihdr.writeUInt32BE\(W, 0\);
ihdr.writeUInt32BE\(H, 4\);
ihdr[8] = 8;  // bit depth
ihdr[9] = 6;  // color type RGBA
ihdr[10] = 0; // compression
ihdr[11] = 0; // filter
ihdr[12] = 0; // interlace

const png = Buffer.concat\([
  sig,
  chunk\('IHDR', ihdr\),
  chunk\('IDAT', compressed\),
  chunk\('IEND', Buffer.alloc\(0\)\)
]\);

fs.writeFileSync\('public/icon-192.png', png\);
console.log\('wrote icon-192.png \(' + png.length + ' bytes\)'\);
" 2>&1)
